from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismListPluginsNode(BaseNode):
    name = "Prism: List Plugins"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("plugin_names", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'plugin_names': [], 'count': 0}
        try:
            names = []
            plugins_module = getattr(core, 'plugins', None)
            if plugins_module is None:
                return {'plugin_names': [], 'count': 0}
            for attr in ('getLoadedPlugins', 'getPlugins', 'loadedPlugins'):
                if hasattr(plugins_module, attr):
                    val = getattr(plugins_module, attr)
                    res = val() if callable(val) else val
                    if isinstance(res, dict): names = list(res.keys())
                    else: names = [str(getattr(p, 'pluginName', p)) for p in (res or [])]
                    break
            self.log_info(f"{len(names)} plugin(s) loaded.")
            return {'plugin_names': names, 'count': len(names)}
        except Exception as e:
            self.log_error(f"listPlugins failed: {e}")
            return {'plugin_names': [], 'count': 0}

def register_node():
    return PrismListPluginsNode
